// https://github.com/DevWar/Coding-Challenges
// Time complexity: O(log n)
// Space complexity: O(1)

#include <bits/stdc++.h>

using namespace std;

class Solution {
public:
    int solve(vector<int>& nums, int target) {
        if (nums.empty())
            return -1;

        int left = 0, right = nums.size() - 1;
        while (left <= right) {
            int mid = left + (right - left) / 2;
            if (nums[mid] == target) {
                if (mid == 0 || nums[mid - 1] != target)
                    return mid;
                right = mid - 1;
            } else if (nums[mid] < target) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return -1;
    }
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);
    Solution s;
    cout << s.solve({-1, 0, 3, 5, 9, 12}, 9) << endl;
    cout << s.solve({-1, 0, 3, 5, 9, 12}, 2) << endl;
    return 0;
}
